INSERT INTO tb_publicacao (id_publicacao, dh_atualizacao, st_aprovado, dh_criacao, no_titulo, tx_conteudo, st_apresentacao, cd_tipo_publicacao) VALUES
  (1, '2025-02-01 13:00:00', TRUE, '2025-01-30 13:00:00', 'Modelagem de Sistemas de Processamento de Linguagem Natural', 'Este trabalho apresenta uma investigacao sobre visao computacional. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', TRUE, 1),
  (2, '2024-04-14 14:00:00', TRUE, '2024-03-26 14:00:00', 'Avaliacao de Desempenho em Computacao Quantica', 'Este trabalho apresenta uma investigacao sobre seguranca de dados. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', TRUE, 1),
  (3, '2024-06-07 10:00:00', TRUE, '2024-05-25 10:00:00', 'Avaliacao de Desempenho em Seguranca de Dados', 'Este trabalho apresenta uma investigacao sobre aprendizado de maquina. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', FALSE, 2),
