  (1487, '2023-07-16 02:00:00', FALSE, '2023-07-09 02:00:00', 'Proposta de Metodologia para Mineracao de Dados', 'Este trabalho apresenta uma investigacao sobre visao computacional. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', FALSE, 2),
  (1488, '2023-09-25 00:00:00', TRUE, '2023-09-19 00:00:00', 'Otimizacao de Algoritmos para Realidade Aumentada', 'Este trabalho apresenta uma investigacao sobre internet das coisas. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', TRUE, 2),
  (1489, '2024-06-11 19:00:00', TRUE, '2024-04-21 19:00:00', 'Aplicacao de Tecnicas de Bioinformatica Aplicada', 'Este trabalho apresenta uma investigacao sobre engenharia de software agil. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', TRUE, 1),
  (1490, '2023-10-08 10:00:00', FALSE, '2023-09-04 10:00:00', 'Investigacao sobre Realidade Aumentada', 'Este trabalho apresenta uma investigacao sobre redes neurais profundas. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', FALSE, 2),
  (1491, '2025-09-25 07:00:00', TRUE, '2025-08-28 07:00:00', 'Avaliacao de Desempenho em Redes Neurais Profundas', 'Este trabalho apresenta uma investigacao sobre engenharia de software agil. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', TRUE, 2),
  (1492, '2024-05-11 18:00:00', FALSE, '2024-04-04 18:00:00', 'Avaliacao de Desempenho em Realidade Aumentada', 'Este trabalho apresenta uma investigacao sobre mineracao de dados. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', FALSE, 2),
  (1493, '2025-03-22 09:00:00', TRUE, '2025-01-21 09:00:00', 'Otimizacao de Algoritmos para Internet das Coisas', 'Este trabalho apresenta uma investigacao sobre visao computacional. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', TRUE, 1),
  (1494, '2023-12-02 06:00:00', TRUE, '2023-11-07 06:00:00', 'Plataforma Distribuida de Realidade Aumentada', 'Este trabalho apresenta uma investigacao sobre bioinformatica aplicada. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', FALSE, 2),
  (1495, '2024-10-18 15:00:00', FALSE, '2024-08-22 15:00:00', 'Modelagem de Sistemas de Redes Neurais Profundas', 'Este trabalho apresenta uma investigacao sobre computacao em nuvem. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', FALSE, 2),
  (1496, '2025-08-03 14:00:00', FALSE, '2025-06-30 14:00:00', 'Uma Abordagem para Realidade Aumentada', 'Este trabalho apresenta uma investigacao sobre blockchain e criptomoedas. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', FALSE, 2),
  (1497, '2023-07-20 10:00:00', TRUE, '2023-07-05 10:00:00', 'Arquitetura Escalavel de Seguranca de Dados', 'Este trabalho apresenta uma investigacao sobre computacao quantica. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', TRUE, 2),
  (1498, '2025-06-27 12:00:00', TRUE, '2025-05-29 12:00:00', 'Investigacao sobre Bancos de Dados Relacionais', 'Este trabalho apresenta uma investigacao sobre redes neurais profundas. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', FALSE, 2),
  (1499, '2025-07-13 19:00:00', TRUE, '2025-05-16 19:00:00', 'Avaliacao de Desempenho em Aprendizado de Maquina', 'Este trabalho apresenta uma investigacao sobre aprendizado de maquina. A metodologia utilizada combina abordagens quantitativas e qualitativas. Os resultados obtidos demonstram a viabilidade da proposta em cenarios reais. Conclui-se que a abordagem apresenta ganhos significativos de desempenho.', FALSE, 1),
